def clean_string(s):
    if isinstance(s, str):
        return s.strip().lower()
    return s

def process_user(user_data):
    name = clean_string(user_data.get("name"))
    email = clean_string(user_data.get("email"))

    if not name:
        return None

    result = {"name": name, "email": email}
    return result

def process_admin(admin_data):
    # Reuse user processing logic
    user_result = process_user(admin_data)

    if user_result is None:
        return None

    # Add admin role
    user_result["role"] = "admin"
    return user_result

